messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "required": [
    "date",
    "lessor",
    "lessee",
    "premises",
    "lease",
    "rent"
  ],
  "properties": {
    "date": {
      "type": "string",
      "format": "date",
      "description": "Date of the lease, formatted as YYYY-MM-DD"
    },
    "rent": {
      "type": "object",
      "required": [
        "monthlyAmount",
        "securityDeposit"
      ],
      "properties": {
        "monthlyAmount": {
          "type": "number"
        },
        "securityDeposit": {
          "type": "number"
        }
      }
    },
    "lease": {
      "type": "object",
      "required": [
        "years",
        "months",
        "startDate",
        "endDate"
      ],
      "properties": {
        "years": {
          "type": "number"
        },
        "months": {
          "type": "number"
        },
        "endDate": {
          "type": "string",
          "format": "date",
          "description": "End date of the lease, formatted as YYYY-MM-DD"
        },
        "startDate": {
          "type": "string",
          "format": "date",
          "description": "Start date of the lease, formatted as YYYY-MM-DD"
        }
      }
    },
    "lessee": {
      "type": "object",
      "required": [
        "name",
        "streetAddress",
        "state"
      ],
      "properties": {
        "name": {
          "type": "string"
        },
        "state": {
          "type": "string"
        },
        "streetAddress": {
          "type": "string"
        }
      }
    },
    "lessor": {
      "type": "object",
      "required": [
        "name",
        "streetAddress",
        "state"
      ],
      "properties": {
        "name": {
          "type": "string"
        },
        "state": {
          "type": "string"
        },
        "streetAddress": {
          "type": "string"
        }
      }
    },
    "premises": {
      "type": "object",
      "required": [
        "squareFeet",
        "spaceType",
        "streetAddress"
      ],
      "properties": {
        "spaceType": {
          "enum": [
            "Office Space",
            "Retail Space",
            "Warehouse",
            "Industrial Space"
          ],
          "type": "string"
        },
        "squareFeet": {
          "type": "string"
        },
        "streetAddress": {
          "type": "string"
        }
      }
    }
  }
}
